function weightedIntervalMax(intervals) {
  const n = intervals.length;
  if (n === 0) return 0;

  // Sort by end time (break ties by start for determinism)
  const sorted = intervals.slice().sort((a, b) => (a[1] - b[1]) || (a[0] - b[0]));

  // p[i]: index of the rightmost interval j < i (in sorted order) whose end <= sorted[i].start, or -1
  const p = new Array(n);
  for (let i = 0; i < n; i++) {
    const start = sorted[i][0];
    let lo = 0, hi = i - 1, best = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (sorted[mid][1] <= start) {
        best = mid;
        lo = mid + 1;
      } else {
        hi = mid - 1;
      }
    }
    p[i] = best;
  }

  // dp[i]: max value using sorted intervals 0..i-1
  const dp = new Array(n + 1);
  dp[0] = 0;
  for (let i = 1; i <= n; i++) {
    const take = sorted[i - 1][2] + dp[p[i - 1] + 1];
    dp[i] = Math.max(dp[i - 1], take);
  }

  return dp[n];
}
